#include <iostream>
using namespace std;
int main()
{
    int a[10],b,c=0;
    for(int i=0;i<10;i++)
        {
            cin>>a[i];
        }
    cin>>b;
    b=b+30;
    for(int i=0;i<10;i++)
        {
            if(a[i]<=b)
            {
                c+=1;
            }
        }
    cout<<c;
    return 0;
}
